/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    constexpr double inv3 = 0.33333;

    // Fast path for tiny arrays (no interior points)
    if (n <= 2) {
        return;
    }

    const int interior = n - 2;                // number of interior indices
    const double *restrict a = A.data();       // original array (read)
    double *restrict b = B.data();             // output array (write)

    for (int t = 0; t < tsteps; ++t) {
        /* First update: B[i] = 1/3 * (A[i-1] + A[i] + A[i+1])   */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second update: A[i] = 1/3 * (B[i-1] + B[i] + B[i+1])   */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
