#include <cstddef>
#include <omp.h>

// Flatten the 2‑D vector into a single contiguous array to improve cache usage.
// The caller must still pass a vector of vectors of the correct size.
// This wrapper will copy the data into a flat buffer, perform the algorithm,
// and copy the result back into the original vector of vectors.
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Allocate a contiguous block: row-major layout
    std::vector<int> flat(n * n);

    // copy original data into the flat buffer
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    // Main Floyd‑Warshall kernel with OpenMP parallelisation.
    // The outer loop over k is vectorised; inner loops are split across threads.
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int kRowIdx = k * n;
        for (int i = 0; i < n; ++i) {
            int iRowIdx = i * n;
            int aik = flat[iRowIdx + k];
            for (int j = 0; j < n; ++j) {
                int tentative = aik + flat[kRowIdx + j];
                if (tentative < flat[iRowIdx + j])
                    flat[iRowIdx + j] = tentative;
            }
        }
    }

    // copy results back into the original 2‑D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n, path[i].begin());
}
