/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    /* Each iteration of the outer loop depends only on
       previously computed rows, so the rows can be processed
       in parallel. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // cache the ith row pointer for faster access
        double* row_i = A[i].data();

        /* j < i : compute off‑diagonal elements */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* row_j = A[j].data();

            /* Accumulate dot product between A[i][k] and A[j][k] */
            for (int k = 0; k < j; ++k) {
                sum += row_i[k] * row_j[k];
            }
            row_i[j] = (row_i[j] - sum) / row_j[j];
        }

        /* i == j : compute diagonal element */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += row_i[k] * row_i[k];
        }
        row_i[i] = std::sqrt(row_i[i] - sum);
    }
}
