/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    const double inv9 = 1.0/9.0;

    /* Flatten access for speed: obtain raw pointers to each row once */
    std::vector<double*> rowPtrs(n);
    for (int i = 0; i < n; ++i)
        rowPtrs[i] = A[i].data();

    /* Perform the update for each time step. */
    for (int t = 0; t < tsteps; ++t) {
        /* Parallelise the inner two loops.  Each iteration is
           independent because we write to A[i][j] only after
           reading all nine surrounding values.  The dependency
           on the previous value of A[i][j] is handled because
           the range of j starts at 1. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            double* const cur  = rowPtrs[i];
            double* const prev = rowPtrs[i-1];
            double* const next = rowPtrs[i+1];
            for (int j = 1; j <= n - 2; ++j) {
                cur[j] = (prev[j-1] + prev[j] + prev[j+1] +
                          cur[j-1]   + cur[j]   + cur[j+1] +
                          next[j-1] + next[j] + next[j+1]) * inv9;
            }
        }
    }
}
