/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    auto match = [](int b1, int b2) {
        return b1 + b2 == 3 ? 1 : 0;
    };

#if defined(_OPENMP)
    #pragma omp parallel for schedule(static)
#endif
    for (int gap = 1; gap < n; ++gap) {
        // The outer loop runs over all pairs (i,j) with j-i = gap.
        // All iterations for a given gap are independent.
#if defined(_OPENMP)
        #pragma omp for schedule(static)
#endif
        for (int i = 0; i + gap < n; ++i) {
            int j = i + gap;
            int best = std::max(table[i][j], table[i][j - 1]);          // left
            best = std::max(best, table[i + 1][j]);                     // right
            if (i + 1 < j) {
                best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
            }
            // Combine sub‑structures
            for (int k = i + 1; k < j; ++k) {
                int temp = table[i][k] + table[k + 1][j];
                if (temp > best) best = temp;
            }
            table[i][j] = best;
        }
    }
}
