/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
		double alpha,
		double beta,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<double>& tmp,
		std::vector<double>& x,
		std::vector<double>& y)
{
    // Take references to the underlying C arrays to avoid repeated bounds
    // checking and indirection.
    std::vector<double*> A_rows(n), B_rows(n);
    for (int i = 0; i < n; ++i) {
        A_rows[i] = A[i].data();
        B_rows[i] = B[i].data();
    }

    const double* xptr = x.data();
    double* tmp_ptr = tmp.data();
    double* yptr   = y.data();

    // Parallelise over the outer loop; each iteration is independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_val = 0.0;
        double y_val   = 0.0;

        const double* Aptr = A_rows[i];
        const double* Bptr = B_rows[i];

        for (int j = 0; j < n; ++j) {
            const double xj = xptr[j];
            tmp_val += Aptr[j] * xj;
            y_val   += Bptr[j] * xj;
        }

        tmp_val *= alpha;
        y_val   = tmp_val + beta * y_val;

        tmp_ptr[i] = tmp_val;
        yptr[i]   = y_val;
    }
}
