#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ----------------------------------------------------------------
       1.  Mean per column (m) -----------------------------------------
       ---------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s / static_cast<double>(n);
    }

    /* ----------------------------------------------------------------
       2.  Center the data (subtract mean) -----------------------------
       ---------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] -= mean[j];
        }
    }

    /* ----------------------------------------------------------------
       3.  Covariance matrix ------------------------------------------
       ---------------------------------------------------------------- */
    const double denom = 1.0 / static_cast<double>(n - 1);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        /* The inner loop is unrolled to keep the upper‑triangular part
           computed once, then copied to the symmetric position.        */
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            cov[i][j] = sum * denom;
            cov[j][i] = cov[i][j];   // fill symmetric entry
        }
    }
}
```
This version keeps the original algorithmic behaviour but:
* uses OpenMP to parallelise all outer loops;  
* performs the mean and centring loops in a single `collapse(2)` to reduce overhead;  
* pre‑computes the denominator once;  
* keeps the covariance computation cache‑friendly and symmetric.

