/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* --- 1st phase: tmp = alpha * A * B --------------------------------- */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < ni; ++i) {
        double* const rowA = A[i].data();
        double* const rowTmp = tmp[i].data();
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += rowA[k] * B[k][j];
            }
            rowTmp[j] = alpha * sum;
        }
    }

    /* --- 2nd phase: D = beta * D + tmp * C -------------------------------- */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < ni; ++i) {
        double* const rowD = D[i].data();
        double* const rowTmp = tmp[i].data();
        for (int j = 0; j < nl; ++j) {
            double sum = rowD[j] * beta;
            for (int k = 0; k < nj; ++k) {
                sum += rowTmp[k] * C[k][j];
            }
            rowD[j] = sum;
        }
    }
}
