void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    /* Parallelise over the outermost dimension (rows of C).
       The inner loops remain sequential to avoid false sharing
       and to keep the data layout contiguous in memory.    */

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double*       Ci = C[i].data();             // row i of result
        const double* Ai = A[i].data();             // row i of A

        // Scale existing C row by beta
        for (int j = 0; j < nj; ++j)
            Ci[j] *= beta;

        // Main GEMM computation
        for (int k = 0; k < nk; ++k) {
            const double aik = alpha * Ai[k];
            const double* Bk = B[k].data();         // row k of B
            for (int j = 0; j < nj; ++j)
                Ci[j] += aik * Bk[j];
        }
    }
