void kernel_lu(int n,
	       std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        // Process the lower part (j < i)
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            const double* Ai = A[i].data();
            const double* Ak = A[i].data();
            const double* Aj = A[j].data();

