            Ai[j] -= sum;
            Ai[j] /= Aj[j];
        }

        // Process the upper part (j >= i)
        for (int j = i; j < n; ++j) {
            double* Aij = A[i].data() + j;
            const double* Ai = A[i].data();

            for (int k = 0; k < i; ++k) {
                *Aij -= Ai[k] * A[k][j];
            }
        }
