/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Flatten the two‑dimensional vectors for faster pointer arithmetic
    // (they are already contiguous row‑major in std::vector).
    const double *aptr = &A[0][0];
    double       *cptr = &C[0][0];

    // Compute strides once
    const std::ptrdiff_t astride = static_cast<std::ptrdiff_t>(m);
    const std::ptrdiff_t cstride = static_cast<std::ptrdiff_t>(n);

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *ai = aptr + i * astride;          // row i of A
        double       *ci = cptr + i * cstride;          // row i of C

        // first zero/scale the lower triangle of this row
        double *cj = ci;                              // j=i downto 0
        for (int j = i; j >= 0; --j) {
            cj[j] *= beta;
        }

        // main accumulation: alpha*A[i][k]*A[j][k]
        for (int k = 0; k < m; ++k) {
            double aik = ai[k];
            const double *ak = aptr + k;               // column k of A in CSR form

            // unroll j loop a little for better instruction-level parallelism
            for (int j = i; j >= 0; j -= 4) {
                int j0 = j;
                double a0 = ak[j0] * aik;
                ci[j0] += alpha * a0;
                if (j0 - 1 >= 0) {
                    double a1 = ak[j0 - 1] * aik;
                    ci[j0 - 1] += alpha * a1;
                }
                if (j0 - 2 >= 0) {
                    double a2 = ak[j0 - 2] * aik;
                    ci[j0 - 2] += alpha * a2;
                }
                if (j0 - 3 >= 0) {
                    double a3 = ak[j0 - 3] * aik;
                    ci[j0 - 3] += alpha * a3;
                }
            }
        }
    }
}
