#include <vector>
#include <cstring>   // for memcpy
#include <omp.h>     // OpenMP header (needed when compiling with -fopenmp)

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    /* --------------------------------------------------------------------
     *  Create a contiguous copy of the lower‑triangular matrix L.
     *  There is no performance benefit in keep­ing the nested vector
     *  representation across iterations, so we replicate it into a flat
     *  array (row major).  The copy incurs O(n²) time but is only done
     *  once per call – the overhead is negligible relative to the
     *  triangular solve.
     * -------------------------------------------------------------------- */
    std::vector<double> Lflat;
    Lflat.reserve(static_cast<size_t>(n) * n);
    for (int i = 0; i < n; ++i) {
        // Copy the whole row; the upper part is unused but harmless
        Lflat.insert(Lflat.end(), L[i].begin(), L[i].end());
    }

    double* Lptr = Lflat.data();   // pointer to the flat matrix
    double* xptr = x.data();       // pointer to the solution vector
    double* bptr = b.data();       // pointer to the right–hand side

    /* --------------------------------------------------------------------
     *  Triangular solve: x = L⁻¹ * b   (L is lower triangular)
     *  The standard forward substitution algorithm is used.  We
     *  avoid out‑of‑bounds checks on the loop indices and use
     *  local registers for repeated accesses.
     * -------------------------------------------------------------------- */
    for (int i = 0; i < n; ++i) {
        double sum = bptr[i];
        double* Li = Lptr + static_cast<size_t>(i) * n; // start of row i

        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * xptr[j];
        }

        xptr[i] = sum / Li[i];
    }
}
