void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Convert the 2‑D std::vector data to flat, contiguous
       memory for maximal cache friendliness. */
    std::vector<double> Af(m * m);
    std::vector<double> Bf(m * n);

    /* Flatten A and B */
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < m; ++j)
            Af[i * m + j] = A[i][j];
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            Bf[i * n + j] = B[i][j];

    /* Main kernel:  B = alpha * A^T * B
       A is MxM (upper part unused).  B is MxN.         */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            /* Only accumulate contributions where k > i          */
#pragma ivdep
            for (int k = i + 1; k < m; ++k) {
                sum += Af[k * m + i] * Bf[k * n + j];
            }
            Bf[i * n + j] = alpha * (Bf[i * n + j] + sum);
        }
    }

    /* Copy results back into the original 2‑D vectors. */
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            B[i][j] = Bf[i * n + j];
}
