    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        y[i] = 0.0;
    }

    /* Main computation: tmp[i] = A[i] ⋅ x, then y += A[i]^T * tmp[i] */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        /* ** 1. Compute tmp[i] ** */
        double dot = 0.0;
        const double* Ai = A[i].data();
        for (int j = 0; j < n; ++j) {
            dot += Ai[j] * x[j];
        }
        tmp[i] = dot;

        /* ** 2. Accumulate into y ** */
        for (int j = 0; j < n; ++j) {
            #pragma omp atomic
            y[j] += Ai[j] * dot;
        }
    }
