                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) noexcept
{
    /* LU decomposition – forward sweep */
    for (int i = 0; i < n; ++i)
    {
        double* const row_i = A[i].data();          // row i of A
        // --- compute sub‑diagonal part (L) -----------------
        for (int j = 0; j < i; ++j)
        {
            double  w = row_i[j];                    // A[i][j]
            const double* const row_k = A[j].data(); // row j of A

            for (int k = 0; k < j; ++k)               // dot product
                w -= row_i[k] * row_k[k];

            A[i][j] = w / row_k[j];                  // divide by pivot
        }

        // --- compute upper part (U) -------------------------
        for (int j = i; j < n; ++j)
        {
            double  w = row_i[j];                    // A[i][j]
            for (int k = 0; k < i; ++k)
                w -= row_i[k] * A[k][j];

            row_i[j] = w;
        }
    }

    /* Forward substitution: Ly = b ---------------------------------*/
    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        const double* const row_i = A[i].data();
        for (int j = 0; j < i; ++j)
            w -= row_i[j] * y[j];
        y[i] = w;
    }

    /* Backward substitution: Ux = y ---------------------------------*/
    for (int i = n - 1; i >= 0; --i)
