void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_n = 1.0 / n;
    const double rinv_n = 1.0 / std::sqrt(n);

    /* ------------------------------------------------------------------
       Step 1 – Compute column means
       ------------------------------------------------------------------ */
    mean.resize(m);
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s * inv_n;
    }

    /* ------------------------------------------------------------------
       Step 2 – Compute column standard deviations
       ------------------------------------------------------------------ */
    stddev.resize(m);
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        const double mval = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mval;
            s += d * d;
        }
        s *= inv_n;
        s = std::sqrt(s);
        stddev[j] = s <= eps ? 1.0 : s;
    }

    /* ------------------------------------------------------------------
       Step 3 – Standardise data (parallelised by rows)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = data[i][j] - mean[j];
            val *= rinv_n / stddev[j];
            data[i][j] = val;
        }
    }

    /* ------------------------------------------------------------------
       Step 4 – Compute correlation matrix
       ------------------------------------------------------------------ */
    corr.resize(m);
    for (auto& row : corr) row.resize(m);

    /* Each element corr[i][j] is the dot product of column i and j.
       Compute the upper triangle and mirror to lower. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double dot = 0.0;
            for (int k = 0; k < n; ++k)
                dot += data[k][i] * data[k][j];
            corr[i][j] = dot;
            corr[j][i] = dot;
        }
    }
}
