/* Modified Gram–Schmidt QR decomposition.
   The signature must match the harness, but the implementation
   has been rewritten for speed on a classic x86‑64 system
   with 8 hardware threads and GCC 13 (‑O2, ‑fopenmp). */
void kernel_gramschmidt(int m, int n,
                       std::vector<std::vector<double>>& A,
                       std::vector<std::vector<double>>& R,
                       std::vector<std::vector<double>>& Q)
{
    /* Expose contiguous memory for better cache behaviour. */
    std::vector<double> Aloc(m * n);
    std::vector<double> Qloc(m * n);
    std::vector<double> Rloc(n * n);

    /* Flatten the 2‑D input into the 1‑D array in column‑major order.
       Working in column‑major avoids cache misses when columns are
       accessed repeatedly. */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < m; ++i)
            Aloc[j * m + i] = A[i][j];

    /* Main algorithm loop. */
    for (int k = 0; k < n; ++k) {
        /* --- 1.  Compute ||A[:,k]|| = scale of k‑th column --- */
        double nrm = 0.0;
        #pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i)
            nrm += Aloc[k * m + i] * Aloc[k * m + i];
        double rk = std::sqrt(nrm);
        Rloc[k * n + k] = rk;

        /* --- 2.  Normalise that column to obtain q_k --- */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Qloc[k * m + i] = Aloc[k * m + i] / rk;

        /* --- 3.  Process all remaining columns --- */
        for (int j = k + 1; j < n; ++j) {
            /* dot product q_k · A[:,j] */
            double rij = 0.0;
            #pragma omp simd reduction(+:rij)
            for (int i = 0; i < m; ++i)
                rij += Qloc[k * m + i] * Aloc[j * m + i];
            Rloc[k * n + j] = rij;

            /* A[:,j] -= q_k * rij */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                Aloc[j * m + i] -= Qloc[k * m + i] * rij;
        }
    }

    /* Flatten results back into the 2‑D containers. */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < m; ++i)
            A[i][j] = Aloc[j * m + i];
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < m; ++i)
            Q[i][j] = Qloc[j * m + i];
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < n; ++i)
            R[i][j] = Rloc[j * n + i];
}
