void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    /* Flatten the 2‑D vectors into 1‑D arrays for better spatial locality. */
    std::vector<double> Af(n * n);
    std::vector<double> Bf(n * n);

    /* Copy the original data into the flattened arrays. */
    __pragma_omp("parallel for collapse(2) schedule(static)")
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            Af[idx(i, j, static_cast<std::size_t>(n))] = A[i][j];

    const double coeff = 0.2;
    const int inner_start = 1;
    const int inner_end   = n - 1;

    for (int t = 0; t < tsteps; ++t) {
        /* 1st half of the Jacobi step : A → B */
        __pragma_omp("parallel for collapse(2) schedule(static)")
        for (int i = inner_start; i < inner_end; ++i) {
            for (int j = inner_start; j < inner_end; ++j) {
                std::size_t p = idx(i, j, static_cast<std::size_t>(n));
                Bf[p] = coeff * ( Af[p]
                                + Af[idx(i, j - 1, static_cast<std::size_t>(n))]
                                + Af[idx(i, j + 1, static_cast<std::size_t>(n))]
                                + Af[idx(i + 1, j, static_cast<std::size_t>(n))]
                                + Af[idx(i - 1, j, static_cast<std::size_t>(n))] );
            }
        }

        /* 2nd half of the Jacobi step : B → A */
        __pragma_omp("parallel for collapse(2) schedule(static)")
        for (int i = inner_start; i < inner_end; ++i) {
            for (int j = inner_start; j < inner_end; ++j) {
                std::size_t p = idx(i, j, static_cast<std::size_t>(n));
                Af[p] = coeff * ( Bf[p]
                               + Bf[idx(i, j - 1, static_cast<std::size_t>(n))]
                               + Bf[idx(i, j + 1, static_cast<std::size_t>(n))]
                               + Bf[idx(i + 1, j, static_cast<std::size_t>(n))]
                               + Bf[idx(i - 1, j, static_cast<std::size_t>(n))] );
