                const std::vector<double>& B_ij   = B[i][j];
                const std::vector<double>& B_ipj1 = B[i][j+1];
                const std::vector<double>& B_imj1 = B[i][j-1];
                std::vector<double>& A_ij = A[i][j];

                for (int k = 1; k < n-1; ++k)
                {
                    double b00 = B_ij[k];
                    double sum = 0.0;
                    sum += B_ip1[k]   - 2.0*b00 + B_im1[k];
                    sum += B_ipj1[k]  - 2.0*b00 + B_imj1[k];
                    sum += B_ij[k+1]  - 2.0*b00 + B_ij[k-1];
                    A_ij[k] = coef * sum + b00;
                }
            }
        }
    }
