#include <vector>

void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    std::vector<double> z(n);                     // temporaries
    double *const rptr = r.data();
    double *const yptr = y.data();
    double *const zptr = z.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k)
    {
        /* update beta */
        beta = (1.0 - alpha * alpha) * beta;

        /* compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i] */
        double sum = 0.0;
        int i = 0;
        for (; i + 3 < k; i += 4)
        {
            sum += rptr[k - i - 1]  * yptr[i]
                 + rptr[k - i - 2]  * yptr[i + 1]
                 + rptr[k - i - 3]  * yptr[i + 2]
                 + rptr[k - i - 4]  * yptr[i + 3];
        }
        for (; i < k; ++i)
        {
            sum += rptr[k - i - 1] * yptr[i];
        }

        /* compute new alpha */
        alpha = -(rptr[k] + sum) / beta;

        /* temporary compute z[i] = y[i] + alpha*y[k-i-1] */
        int j = 0;
        for (; j + 3 < k; j += 4)
        {
            zptr[j]   = yptr[j]   + alpha * yptr[k - j - 1];
            zptr[j+1] = yptr[j+1] + alpha * yptr[k - j - 2];
            zptr[j+2] = yptr[j+2] + alpha * yptr[k - j - 3];
            zptr[j+3] = yptr[j+3] + alpha * yptr[k - j - 4];
        }
        for (; j < k; ++j)
        {
            zptr[j] = yptr[j] + alpha * yptr[k - j - 1];
        }

        /* copy back to y[0..k-1] */
        for (int l = 0; l < k; ++l)
            yptr[l] = zptr[l];

        yptr[k] = alpha;
    }
}
