#include <omp.h>

/* Main computational kernel. The whole function will be timed,
 * including the call and return. */
/* Optimised version – preserves the exact behaviour of the original. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Convert 2‑D vectors to 1‑D workspace for fast cache access */
    const std::size_t N = static_cast<std::size_t>(w) * h;
    std::vector<float> in(N), out(N), Y1(N), Y2(N);
    auto idx = [h](int i, int j) -> std::size_t { return static_cast<std::size_t>(i) * h + j; };

    /* Flatten the input matrix */
    for (int i = 0; i < w; ++i)
        std::copy(imgIn[i].begin(), imgIn[i].end(), in.begin() + i * h);

    /* Pre‑compute constants */
    const float falpha = static_cast<float>(alpha);
    const float expA  = std::exp(-falpha);
    const float k = 1.0f - expA * (1.0f - expA) /
                     (1.0f + 2.0f * falpha * expA - std::exp(2.0f * falpha));

    const float a1 =  a5 = k;
    const float a2 =  a6 = k * expA * (falpha - 1.0f);
    const float a3 =  a7 = k * expA * (falpha + 1.0f);
    const float a4 =  a8 = -k * std::exp(-2.0f * falpha);
    const float b1 = std::pow(2.0f, -falpha);
    const float b2 = -std::exp(-2.0f * falpha);
    const float c  = 1.0f;            // c1 = c2 = 1

    /* 1. Forward row filtering – y1 */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        std::size_t base = static_cast<std::size_t>(i) * h;
        for (int j = 0; j < h; ++j) {
            float x = in[base + j];
            Y1[base + j] = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = x;  ym2 = ym1;  ym1 = Y1[base + j];
        }
    }

    /* 2. Backward row filtering – y2 */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        std::size_t base = static_cast<std::size_t>(i) * h;
        for (int j = h-1; j >= 0; --j) {
            float x = in[base + j];
            Y2[base + j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;  xp1 = x;  yp2 = yp1;  yp1 = Y2[base + j];
        }
    }

    /* 3. Sum row results into out */
    #pragma omp parallel for schedule(static)
    for (std::size_t p = 0; p < N; ++p)
        out[p] = c * (Y1[p] + Y2[p]);

    /* 4. Forward column filtering on the row‑filtered result – y1 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            std::size_t idx = i * h + j;
            float x = out[idx];
            Y1[idx] = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = x;  ym2 = ym1;  ym1 = Y1[idx];
        }
    }

    /* 5. Backward column filtering on the row‑filtered result – y2 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            std::size_t idx = i * h + j;
            float x = out[idx];
            Y2[idx] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;  tp1 = x;  yp2 = yp1;  yp1 = Y2[idx];
        }
    }

    /* 6. Final accumulation – back to out */
    #pragma omp parallel for schedule(static)
    for (std::size_t p = 0; p < N; ++p)
        out[p] = c * (Y1[p] + Y2[p]);

    /* Copy result back to the 2‑D vector format */
    for (int i = 0; i < w; ++i)
        std::copy(out.begin() + i * h, out.begin() + (i+1) * h, imgOut[i].begin());
}
