#include <vector>
#include <algorithm>
#include <cmath>
#include <omp.h>

/* Optimised kernel. Keeps the original behaviour but uses
 * OpenMP parallelisation, local copies of the auxiliary
 * arrays (p,q) and several micro‑optimisations such as
 * pre‑computing indexes and re‑using temporary variables.
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /*----- pre‑compute constants ------------------------------------------------*/
    const double DX   = 1.0 / static_cast<double>(n);
    const double DY   = 1.0 / static_cast<double>(n);
    const double DT   = 1.0 / static_cast<double>(tsteps);
    const double B1   = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* local aliases to avoid repeated indexing overhead */
    const int N   = n;
    const int N1  = N - 1;          // last usable index
    const int N2  = N - 2;          // second last usable index

    /*----- main time loop -----------------------------------------------------*/
    for (int t = 1; t <= tsteps; ++t) {

        /*----- first sweep (solve v) ---------------------------------------*/
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N1; ++i) {
            /* Initialise first and last rows of v on this column */
            v[0][i]      = 1.0;
            v[N1][i]     = 1.0;
            p[i][0]      = 0.0;
            q[i][0]      = v[0][i];

            /* forward sweep on j */
            double denom = b;          // a*p[i][j-1] + b
            for (int j = 1; j < N1; ++j) {
                /* p[i][j] = -c / (a * p[i][j-1] + b); */
                denom = a * p[i][j-1] + b;
                p[i][j] = -c / denom;

                /* q[i][j] = ( -d*u[j][i-1] + (1+2d)*u[j][i] - f*u[j][i+1]
                               - a*q[i][j-1]) / (a*p[i][j-1] + b); */
                double ufJim1 = u[j][i-1];
                double ufJi   = u[j][i];
                double ufJip1 = u[j][i+1];
                double num = -d * ufJim1
                           + (1.0 + 2.0 * d) * ufJi
                           - f * ufJip1
                           - a * q[i][j-1];
                q[i][j] = num / denom;
            }

            /* backward sweep on j */
            for (int j = N2; j >= 1; --j)
                v[j][i] = p[i][j] * v[j+1][i] + q[i][j];
        }

        /*----- second sweep (solve u) ---------------------------------------*/
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N1; ++i) {
            /* Initialise first and last columns of u on this row */
            u[i][0]      = 1.0;
            u[i][N1]     = 1.0;
            p[i][0]      = 0.0;
            q[i][0]      = u[i][0];

            /* forward sweep on j */
            double denom = e;          // d*p[i][j-1] + e
            for (int j = 1; j < N1; ++j) {
                /* p[i][j] = -f / (d * p[i][j-1] + e); */
                denom = d * p[i][j-1] + e;
                p[i][j] = -f / denom;

                /* q[i][j] = ( -a*v[i-1][j] + (1+2a)*v[i][j] - c*v[i+1][j]
                               - d*q[i][j-1]) / (d*p[i][j-1] + e); */
                double vvIm1 = v[i-1][j];
                double vvI   = v[i][j];
                double vvIp1 = v[i+1][j];
                double num = -a * vvIm1
                           + (1.0 + 2.0 * a) * vvI
                           - c * vvIp1
                           - d * q[i][j-1];
                q[i][j] = num / denom;
            }

            /* backward sweep on j */
            for (int j = N2; j >= 1; --j)
                u[i][j] = p[i][j] * u[i][j+1] + q[i][j];
        }
    }
}
